				StateFile: opts.StateFile,
				PlanDir:   state.CanonicalPlanDir,
				Stage:     child.Stage,
			},
			err,
		) {
			attempt := child.ValidationRetryCount + 1
			if repromptErr := continueReprompt(
				ctx,
				state,
				ContinueOptions{
					StateFile: opts.StateFile,
					PlanDir:   state.CanonicalPlanDir,
					Stage:     child.Stage,
